using System;
using System.Diagnostics;
using System.IO;
using System.IO.Compression;
using System.Reflection;
using System.Text;
using System.Windows.Forms;

[assembly: AssemblyTitle("NyxNova Installer")]
[assembly: AssemblyVersion("1.0.0.0")]

class Program {
    // PS1 eingebettet als Base64
    static readonly string PS1_B64 = "";
    static readonly string SPLASH_B64 = "";

    [STAThread]
    static void Main() {
        string tempDir = Path.Combine(Path.GetTempPath(), "NyxNovaLauncher-" + Guid.NewGuid().ToString("N"));
        string ps1Path = Path.Combine(tempDir, "NyxNova-GitHub-Installer.ps1");

        try {
            Directory.CreateDirectory(tempDir);
            byte[] ps1Bytes = Convert.FromBase64String(PS1_B64);
            File.WriteAllBytes(ps1Path, ps1Bytes);
            string splashPath = System.IO.Path.Combine(tempDir, "nyxnova-installer-splash.png");
            byte[] splashBytes = Convert.FromBase64String(SPLASH_B64);
            File.WriteAllBytes(splashPath, splashBytes);

            var psi = new ProcessStartInfo {
                FileName = "powershell.exe",
                Arguments = string.Format("-NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File \"{0}\"", ps1Path),
                UseShellExecute = false,
                CreateNoWindow = true,
                WindowStyle = ProcessWindowStyle.Hidden
            };

            var proc = Process.Start(psi);
            proc.WaitForExit();
        } catch (Exception ex) {
            MessageBox.Show("Fehler beim Starten des Installers:\n\n" + ex.Message, "NyxNova Installer", MessageBoxButtons.OK, MessageBoxIcon.Error);
        } finally {
            try { Directory.Delete(tempDir, true); } catch {}
        }
    }
}